/*
  ============================================================
  NODE: VALIDA ENTRADA CRM
  ============================================================

  OBJETIVO DO NODE
  ------------------------------------------------------------
  Este node é a primeira etapa real do subworkflow do Analista CRM.

  Ele NÃO calcula regra de quantidade.
  Ele NÃO interpreta mensagem.
  Ele NÃO atualiza estado do lead.
  Ele NÃO decide sexo, castração, preço, pagamento ou agenda.

  Ele apenas valida e normaliza tecnicamente a entrada recebida pelo Start.

  O fluxo principal já calculou:
  - qtd_messages
  - contexto_anterior_limit
  - payload_base

  Portanto, este node só garante que esses dados chegaram válidos antes
  de buscar mensagens no Chatwoot e preparar o contexto para a IA.

  ENTRADA ESPERADA
  ------------------------------------------------------------
  {
    account_id: number,
    conversation_id: number,
    processar_IA: boolean,
    qtd_messages: number,
    contexto_anterior_limit: number,
    nome_agente: string,
    payload_base: {
      inputs: {...},
      memory: {...},
      chatwoot: {...},
      message: {...},
      lead: {...},
      agent_name: "Bruna",
      should_reply: true
    }
  }

  SAÍDA ESPERADA
  ------------------------------------------------------------
  O mesmo payload, enriquecido com:

  {
    current_message_id,
    account_id,
    conversation_id,
    processar_IA,
    qtd_messages,
    contexto_anterior_limit,
    nome_agente,
    payload_base,
    valida_entrada_crm_debug
  }

  REGRA DE OURO
  ------------------------------------------------------------
  O fluxo principal decide quantidade.
  Este node só protege contra entrada quebrada.

  Se vier:
  - account_id vazio
  - conversation_id vazio
  - payload_base vazio
  - payload_base.chatwoot.message_id vazio

  O node quebra com erro claro, porque seguir sem isso gera loop,
  histórico errado e resposta ruim da Bruna.
*/

// ============================================================
// 1. LÊ ITEM DO START
// ============================================================

const item = $input.first()?.json || {};

// ============================================================
// 2. HELPERS
// ============================================================

function isObj(value) {
  return value && typeof value === 'object' && !Array.isArray(value);
}

function clean(value) {
  if (value === undefined || value === null) return '';

  if (typeof value === 'object') {
    try {
      return JSON.stringify(value);
    } catch (e) {
      return '';
    }
  }

  return String(value)
    .replace(/\[object Object\]/gi, '')
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
    .replace(/\uFFFD/g, ' ')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .trim();
}

function norm(value) {
  return clean(value)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase();
}

function toNumberOrNull(value) {
  const n = Number(value);
  return Number.isFinite(n) ? n : null;
}

function toBoolean(value, fallback = false) {
  if (value === true) return true;
  if (value === false) return false;
  if (value === 1 || value === '1') return true;
  if (value === 0 || value === '0') return false;

  const v = norm(value);

  if (['true', 'sim', 'yes', 'y'].includes(v)) return true;
  if (['false', 'nao', 'não', 'no', 'n'].includes(v)) return false;

  return fallback;
}

function clampNumber(value, fallback, min, max) {
  const n = Number(value);

  if (!Number.isFinite(n)) return fallback;
  if (n < min) return min;
  if (n > max) return max;

  return Math.round(n);
}

function removeDebugFields(value) {
  /*
    Remove debug temporário caso algum payload antigo ainda venha contaminado.

    Esse subworkflow precisa trabalhar com estado operacional limpo.
    Debug pode existir no topo da execução, mas não dentro do payload_base.
  */

  if (Array.isArray(value)) {
    return value.map(removeDebugFields);
  }

  if (value && typeof value === 'object') {
    const output = {};

    for (const [key, val] of Object.entries(value)) {
      const isDebugField =
        key.endsWith('_debug') ||
        key === 'prepara_estado_bruna_debug' ||
        key === 'nullable_normalizer_debug' ||
        key === 'historico_atualizado_debug' ||
        key === 'calcula_qtd_msg_crm_debug' ||
        key === 'valida_entrada_crm_debug';

      if (isDebugField) continue;

      output[key] = removeDebugFields(val);
    }

    return output;
  }

  return value;
}

// ============================================================
// 3. EXTRAI E LIMPA payload_base
// ============================================================

const payloadBaseRaw = item.payload_base;

if (!isObj(payloadBaseRaw)) {
  throw new Error('VALIDA ENTRADA CRM bloqueado: payload_base ausente ou inválido.');
}

// Remove debug antes de seguir para não carregar lixo técnico para o Analista CRM.
const payloadBase = removeDebugFields(payloadBaseRaw);

const payloadInputs = isObj(payloadBase.inputs) ? payloadBase.inputs : {};
const payloadMemory = isObj(payloadBase.memory) ? payloadBase.memory : {};
const payloadChatwoot = isObj(payloadBase.chatwoot) ? payloadBase.chatwoot : {};
const payloadMessage = isObj(payloadBase.message) ? payloadBase.message : {};
const payloadLead = isObj(payloadBase.lead) ? payloadBase.lead : {};

// ============================================================
// 4. VALIDA OBJETOS ESSENCIAIS DO payload_base
// ============================================================

if (!isObj(payloadBase.inputs)) {
  throw new Error('VALIDA ENTRADA CRM bloqueado: payload_base.inputs ausente.');
}

if (!isObj(payloadBase.chatwoot)) {
  throw new Error('VALIDA ENTRADA CRM bloqueado: payload_base.chatwoot ausente.');
}

if (!isObj(payloadBase.message)) {
  throw new Error('VALIDA ENTRADA CRM bloqueado: payload_base.message ausente.');
}

if (!isObj(payloadBase.lead)) {
  throw new Error('VALIDA ENTRADA CRM bloqueado: payload_base.lead ausente.');
}

// ============================================================
// 5. NORMALIZA IDS PRINCIPAIS
// ============================================================

/*
  account_id e conversation_id chegam direto no Start,
  mas também existem dentro do payload_base.chatwoot.

  Prioridade:
  1. campo direto do Start
  2. payload_base.chatwoot

  Isso mantém compatibilidade com outros usos do subworkflow.
*/

const accountId = toNumberOrNull(
  item.account_id ?? payloadChatwoot.account_id
);

const conversationId = toNumberOrNull(
  item.conversation_id ?? payloadChatwoot.conversation_id
);

const currentMessageId = toNumberOrNull(
  item.current_message_id ??
  payloadChatwoot.message_id ??
  payloadMessage.id
);

const contactId = toNumberOrNull(
  payloadChatwoot.contact_id
);

const inboxId = toNumberOrNull(
  payloadChatwoot.inbox_id
);

if (!accountId) {
  throw new Error('VALIDA ENTRADA CRM bloqueado: account_id vazio ou inválido.');
}

if (!conversationId) {
  throw new Error('VALIDA ENTRADA CRM bloqueado: conversation_id vazio ou inválido.');
}

const precisaBuscarHistorico =
  payloadBase.precisa_buscar_historico === true ||
  payloadBase.fup_automatico_sem_message_id === true ||
  payloadBase.message?.precisa_buscar_historico === true ||
  payloadBase.chatwoot?.precisa_buscar_historico === true;

if (!currentMessageId && !precisaBuscarHistorico) {
  throw new Error('VALIDA ENTRADA CRM bloqueado: payload_base.chatwoot.message_id vazio ou inválido.');
}

// ============================================================
// 6. VALIDA IDENTIDADE DO LEAD
// ============================================================

const resumoLead = isObj(payloadInputs.resumo_lead)
  ? payloadInputs.resumo_lead
  : {};

const phone = clean(
  payloadLead.phone ||
  resumoLead.tutor_telefone ||
  payloadBase.phone ||
  ''
);

if (!phone) {
  throw new Error('VALIDA ENTRADA CRM bloqueado: telefone do lead vazio no payload_base.');
}

const nomeAgente = clean(
  item.nome_agente ||
  payloadBase.agent_name ||
  'Bruna'
);

// ============================================================
// 7. NORMALIZA FLAGS E LIMITES TÉCNICOS
// ============================================================

/*
  IMPORTANTE:
  O cálculo de qtd_messages e contexto_anterior_limit já foi feito
  no fluxo principal.

  Aqui fazemos apenas proteção técnica.

  Não é regra de negócio.
  É defesa contra execução manual, pin data antigo ou integração quebrada.
*/

const processarIA = toBoolean(item.processar_IA, true);

const qtdMessages = clampNumber(
  item.qtd_messages,
  100,
  10,
  200
);

const contextoAnteriorLimit = clampNumber(
  item.contexto_anterior_limit,
  15,
  5,
  50
);

// ============================================================
// 8. VALIDA MENSAGEM ATUAL
// ============================================================

/*
  message.content é a mensagem atual do lead que disparou o fluxo.

  Se vier vazia e não tiver anexo, normalmente é erro de payload.
  Mas não bloqueamos quando há anexo, porque pode ser imagem/documento/áudio.
*/

const messageContent = clean(payloadMessage.content || payloadMessage.content_raw);
const hasAttachment =
  payloadMessage.has_attachment === true ||
  Boolean(payloadMessage.data_url);

const messageType = clean(payloadMessage.type || 'incoming');

if (!messageContent && !hasAttachment) {
  throw new Error('VALIDA ENTRADA CRM bloqueado: mensagem atual vazia e sem anexo.');
}

if (messageType && messageType !== 'incoming') {
  /*
    Não quebra. Só registra no debug.
    Pode existir uso futuro do subworkflow com outro tipo de evento.
  */
}

// ============================================================
// 9. MONTA SAÍDA NORMALIZADA PARA OS PRÓXIMOS NODES
// ============================================================

return [
  {
    json: {
      // Campos diretos usados pelos nodes de busca no Chatwoot.
      account_id: accountId,
      conversation_id: conversationId,
      processar_IA: processarIA,
      qtd_messages: qtdMessages,
      contexto_anterior_limit: contextoAnteriorLimit,
      nome_agente: nomeAgente,

      // ID da mensagem atual. O PREPARA CONTEXTO CRM usará isso para
      // encontrar o bloco atual contínuo do lead.
      current_message_id: currentMessageId || null,
      precisa_buscar_historico: precisaBuscarHistorico,
      fup_automatico_sem_message_id: payloadBase.fup_automatico_sem_message_id === true,

      // Payload limpo, preservado para o Analista CRM e para o retorno final.
      payload_base: payloadBase,

      // Atalhos úteis para os nodes seguintes.
      phone,
      contact_id: contactId,
      inbox_id: inboxId,

      // Debug enxuto para auditoria.
      valida_entrada_crm_debug: {
        ok: true,
        node: 'VALIDA ENTRADA CRM',

        account_id: accountId,
        conversation_id: conversationId,
        contact_id: contactId,
        inbox_id: inboxId,

        current_message_id: currentMessageId,
        phone,
        nome_agente: nomeAgente,

        processar_IA: processarIA,
        qtd_messages: qtdMessages,
        contexto_anterior_limit: contextoAnteriorLimit,

        payload_base_tem_inputs: isObj(payloadBase.inputs),
        payload_base_tem_memory: isObj(payloadBase.memory),
        payload_base_tem_chatwoot: isObj(payloadBase.chatwoot),
        payload_base_tem_message: isObj(payloadBase.message),
        payload_base_tem_lead: isObj(payloadBase.lead),

        message_type: messageType,
        message_has_content: Boolean(messageContent),
        message_has_attachment: Boolean(hasAttachment),
        message_preview: messageContent.slice(0, 180)
      }
    }
  }
];

/*
  ============================================================
  NODE: PREPARA CONTEXTO CRM
  ============================================================

  OBJETIVO
  ------------------------------------------------------------
  Preparar um contexto enxuto para o Analista CRM, mantendo o contrato
  padrão usado pela Bruna:

  {
    inputs,
    message,
    chatwoot,
    memory,
    lead,
    agent_name,
    should_reply
  }

  Este node:
  1. Recebe mensagens vindas do Chatwoot.
  2. Deduplica por ID.
  3. Ordena em ordem cronológica.
  4. Remove ruído operacional.
  5. Identifica quem falou: lead, Bruna, humano, nota humana, nota Convertix ou sistema.
  6. Converte transcrição interna de áudio em fala do lead quando aplicável.
  7. Representa anexos sem texto com placeholder curto.
  8. Encontra a mensagem atual.
  9. Monta o bloco atual contínuo do lead.
  10. Monta o histórico textual para o CRM.
  11. Preserva apenas o que o Analista CRM realmente precisa.

  NÃO FAZ
  ------------------------------------------------------------
  Este node NÃO interpreta semanticamente o lead.

  Ele não decide:
  - se "macho" significa sexo do cão
  - se "sim" significa castrado
  - se a raça é aceita
  - se deve cobrar Pix
  - se deve encerrar conversa
  - se deve repassar humano

  Isso fica para o Analista CRM e para a Bruna.

  SAÍDA FINAL
  ------------------------------------------------------------
  A saída é enxuta. Sem:
  - payload_base
  - arrays completos de mensagens
  - attachments
  - data_url
  - source_id
  - ids auxiliares
  - contexto_anterior_for_crm
  - current_lead_block_text duplicado
  - mensagens humanas separadas que já aparecem no history_for_crm
*/

// ============================================================
// 1. LÊ CONFIGURAÇÃO VALIDADA
// ============================================================

const cfg = $('VALIDA ENTRADA CRM').first().json || {};

const payloadBase = cfg.payload_base || {};
const payloadInputs = payloadBase.inputs || {};
const payloadChatwoot = payloadBase.chatwoot || {};
const payloadMessage = payloadBase.message || {};

const currentMessageId = Number(cfg.current_message_id || payloadChatwoot.message_id || 0);
const contextoAnteriorLimit = clampNumber(cfg.contexto_anterior_limit, 15, 5, 50);
const qtdMessages = clampNumber(cfg.qtd_messages, 100, 10, 200);
const nomeAgente = clean(cfg.nome_agente || payloadBase.agent_name || 'Bruna');

// ============================================================
// 2. HELPERS GERAIS
// ============================================================

function clean(value, preserveNewLines = false) {
  let text = '';

  if (value === undefined || value === null) {
    text = '';
  } else if (typeof value === 'object') {
    try {
      text = JSON.stringify(value);
    } catch (e) {
      text = '';
    }
  } else {
    text = String(value);
  }

  text = text
    .replace(/\[object Object\]/gi, '')
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
    .replace(/\uFFFD/g, ' ')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n');

  if (preserveNewLines) {
    return text
      .split('\n')
      .map(line => line.replace(/[ \t]+/g, ' ').trim())
      .filter(Boolean)
      .join('\n')
      .trim();
  }

  return text
    .replace(/\s+/g, ' ')
    .trim();
}

function norm(value) {
  return clean(value)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase();
}

function toNumberOrNull(value) {
  if (value === undefined || value === null || String(value).trim() === '') return null;

  const n = Number(value);
  return Number.isFinite(n) ? n : null;
}

function clampNumber(value, fallback, min, max) {
  const n = Number(value);

  if (!Number.isFinite(n)) return fallback;
  if (n < min) return min;
  if (n > max) return max;

  return Math.round(n);
}

function cloneObj(value) {
  if (!value || typeof value !== 'object' || Array.isArray(value)) return {};
  return { ...value };
}

function dedupeObservationText(value) {
  const text = clean(value || '', true);
  if (!text) return '';

  const pieces = text
    .match(/[^.!?]+[.!?]?/g)
    ?.map(x => x.trim())
    .filter(Boolean) || [];

  const seen = new Set();
  const out = [];

  for (const piece of pieces) {
    const key = norm(piece);
    if (!key || seen.has(key)) continue;

    seen.add(key);
    out.push(piece);
  }

  return out.join(' ').trim();
}

// ============================================================
// 3. EXTRAI MENSAGENS DO INPUT DO MERGE
// ============================================================

/*
  Aceita múltiplos formatos porque o Merge/HTTP pode entregar:
  - vários itens individuais
  - payload: []
  - messages: []
  - data.payload: []
  - data.messages: []
*/

const inputItems = $input.all();
const rawMessages = [];

for (const item of inputItems) {
  const json = item.json || {};

  if (Array.isArray(json.payload)) {
    rawMessages.push(...json.payload);
    continue;
  }

  if (Array.isArray(json.messages)) {
    rawMessages.push(...json.messages);
    continue;
  }

  if (Array.isArray(json.data?.payload)) {
    rawMessages.push(...json.data.payload);
    continue;
  }

  if (Array.isArray(json.data?.messages)) {
    rawMessages.push(...json.data.messages);
    continue;
  }

  if (json && typeof json === 'object' && json.id !== undefined && json.id !== null) {
    rawMessages.push(json);
  }
}

// ============================================================
// 4. CRIA MENSAGEM SINTÉTICA SE A BUSCA NÃO TROUXER A ATUAL
// ============================================================

/*
  Proteção contra paginação falha ou busca incompleta.
  Se a mensagem atual não vier do Chatwoot, cria uma versão mínima a partir
  do payload_base.message.
*/

const rawHasCurrent = rawMessages.some(m => Number(m?.id) === currentMessageId);

if (!rawHasCurrent && currentMessageId > 0) {
  const syntheticAttachments = [];

  if (payloadMessage.data_url || payloadMessage.has_attachment === true) {
    syntheticAttachments.push({
      data_url: payloadMessage.data_url || '',
      file_type: payloadMessage.message_modality || 'attachment'
    });
  }

  rawMessages.push({
    id: currentMessageId,
    content: payloadMessage.content || payloadMessage.content_raw || '',
    inbox_id: payloadChatwoot.inbox_id || null,
    conversation_id: payloadChatwoot.conversation_id || cfg.conversation_id || null,
    message_type: 0,
    content_type: 'text',
    status: 'sent',
    content_attributes: {},
    created_at: payloadMessage.created_at || null,
    private: false,
    sender: {
      type: 'contact',
      name: payloadBase.lead?.sender_name || '',
      phone_number: payloadBase.lead?.phone || ''
    },
    attachments: syntheticAttachments,
    __synthetic_current_message: true
  });
}

// ============================================================
// 5. DEDUPLICA MENSAGENS BRUTAS POR ID
// ============================================================

const rawById = new Map();

for (const msg of rawMessages) {
  const id = toNumberOrNull(msg?.id);
  if (!id) continue;

  rawById.set(id, msg);
}

const uniqueRawMessages = Array.from(rawById.values())
  .sort((a, b) => Number(a.id) - Number(b.id));

const rawMessageMap = new Map();

for (const msg of uniqueRawMessages) {
  rawMessageMap.set(Number(msg.id), msg);
}

// ============================================================
// 6. HELPERS DE MENSAGEM
// ============================================================

function getAttachments(msg) {
  if (Array.isArray(msg?.attachments)) return msg.attachments;
  if (Array.isArray(msg?.files)) return msg.files;
  return [];
}

function getAttachmentKind(msg) {
  const first = getAttachments(msg)[0] || {};

  const fileType = String(
    first.file_type ||
    first.type ||
    first.content_type ||
    first.mime_type ||
    ''
  ).toLowerCase();

  if (fileType.includes('image')) return 'image';
  if (fileType.includes('audio')) return 'audio';
  if (fileType.includes('video')) return 'video';
  if (fileType.includes('pdf')) return 'document';
  if (fileType.includes('document')) return 'document';
  if (fileType.includes('application')) return 'document';
  if (fileType.includes('file')) return 'document';

  return getAttachments(msg).length ? 'attachment' : '';
}

function senderName(msg) {
  return clean(
    msg?.sender?.name ||
    msg?.sender?.available_name ||
    msg?.sender_name ||
    ''
  );
}

function senderType(msg) {
  return clean(
    msg?.sender?.type ||
    msg?.sender_type ||
    ''
  ).toLowerCase();
}

function isLeadMessage(msg) {
  return Number(msg?.message_type) === 0;
}

function isOutgoingMessage(msg) {
  return Number(msg?.message_type) === 1;
}

function isSystemMessage(msg) {
  return Number(msg?.message_type) === 2;
}

function isPrivate(msg) {
  return msg?.private === true;
}

function isBotAgent(msg) {
  /*
    Regra operacional da AuAu:

    Bruna no Chatwoot pode sair por:
    - Convertix
    - Ricardo Fiorelli

    Qualquer outro sender user deve ser tratado como humano.
  */

  const name = norm(senderName(msg));
  const type = senderType(msg);

  if (type !== 'user') return false;

  const senderId = Number(msg?.sender?.id || 0);

  return (
    senderId === 17 ||
    senderId === 1 ||
    name === 'convertix' ||
    name === 'ricardo fiorelli'
  );
}

function isHumanAgent(msg) {
  /*
    Qualquer usuário do Chatwoot que NÃO seja Convertix/Ricardo
    é humano.

    Isso evita classificar Flávia, Renata, Isa ou qualquer atendente
    como se fosse saída da Bruna.
  */

  const type = senderType(msg);

  return type === 'user' && !isBotAgent(msg);
}

function isDeletedMessage(msg) {
  const content = norm(msg?.content || '');

  return (
    msg?.content_attributes?.deleted === true ||
    content === 'esta mensagem foi excluida' ||
    content === 'mensagem excluida'
  );
}

function isInternalAudioTranscription(msg) {
  const content = String(msg?.content || '');

  return (
    isOutgoingMessage(msg) &&
    isPrivate(msg) &&
    /\[TRANSCRIÇÃO INTERNA DO ÁUDIO/i.test(content)
  );
}

function extractAudioOriginalMessageId(msg) {
  const content = String(msg?.content || '');

  const fromText = content.match(/msg_id\s+(\d+)/i);
  if (fromText?.[1]) return Number(fromText[1]);

  const fromReply = toNumberOrNull(msg?.content_attributes?.in_reply_to);
  if (fromReply) return fromReply;

  return null;
}

function extractAudioTranscriptionText(msg) {
  let text = String(msg?.content || '');

  text = text
    .replace(/\[TRANSCRIÇÃO INTERNA DO ÁUDIO[^\]]*\]/gi, '')
    .replace(/⬇️\s*Transcrição do áudio\s*⬇️[^\n]*/gi, '')
    .replace(/- aproximadamente [^\n]*/gi, '');

  return clean(text, true);
}

function isTechnicalPrivateNote(msg) {
  const content = norm(msg?.content || '');

  return (
    isPrivate(msg) &&
    (
      content.includes('conversa transcrita pela bruna para auto-aprendizado') ||
      content.includes('auto aprendizado') ||
      content.includes('auto-aprendizado') ||
      content.includes('bruna desligada nesta conversa') ||
      content.includes('bruna desligada na conversa') ||
      content.includes('bruna ligada nesta conversa') ||
      content.includes('bruna ligada na conversa')
    )
  );
}

function isConvertixImportantPrivateNote(msg) {
  if (isInternalAudioTranscription(msg)) return false;

  const content = norm(msg?.content || '');
  const name = norm(senderName(msg));
  const senderId = Number(msg?.sender?.id || 0);

  const isConvertixSender =
    senderId === 17 ||
    name === 'convertix';

  if (!isPrivate(msg)) return false;
  if (!isOutgoingMessage(msg)) return false;
  if (!isConvertixSender) return false;

  const looksLikeFormNote =
    content.includes('chegou novo lead formulario') ||
    content.includes('respostas formulario') ||
    content.includes('-- respostas formulario --');

  const hasFormFields =
    content.includes('tipo hospedagem') ||
    content.includes('idade cao') ||
    content.includes('sexo:') ||
    content.includes('porte:') ||
    content.includes('raca:');

  const hasTrackingOrIdentity =
    content.includes('campanha:') ||
    content.includes('publico:') ||
    content.includes('anuncio:') ||
    content.includes('phone:') ||
    content.includes('nome:');

  return looksLikeFormNote || (hasFormFields && hasTrackingOrIdentity);
}

function isImportantSystemText(text) {
  const t = norm(text);

  return (
    t.includes('humano assumiu') ||
    t.includes('desatribuido') ||
    t.includes('desatribuído') ||
    t.includes('atribuido') ||
    t.includes('atribuído') ||
    t.includes('conversa foi reaberta') ||
    t.includes('removeu 01-bruna-atendimento') ||
    t.includes('adicionou 01-humano-assumiu') ||
    t.includes('adicionou 01-bruna-atendimento')
  );
}

function isRelevantText(text, role) {
  const t = clean(text);

  if (!t) return false;

  /*
    Não removemos respostas curtas como "sim", "não", "macho", "fêmea",
    porque elas costumam ser justamente a resposta para a última pergunta.
  */
  if (/^(ok|obrigado|obrigada|obg|valeu|👍|👌|🙏|❤️|❤|kkk|rs|rsrs)$/i.test(t)) {
    return false;
  }

  if (/^esta mensagem foi exclu[ií]da$/i.test(t)) return false;

  if (role === 'sistema' && !isImportantSystemText(t)) return false;

  return true;
}

function roleFromMessage(msg, originalMsgForTranscript = null) {
  if (isInternalAudioTranscription(msg)) {
    if (originalMsgForTranscript && isLeadMessage(originalMsgForTranscript)) return 'lead';
    if (originalMsgForTranscript && isHumanAgent(originalMsgForTranscript)) return 'humano';
    if (originalMsgForTranscript && isOutgoingMessage(originalMsgForTranscript)) return 'bruna';

    return 'lead';
  }

  if (isConvertixImportantPrivateNote(msg)) return 'nota_convertix';

  if (isLeadMessage(msg)) return 'lead';
  if (isSystemMessage(msg)) return 'sistema';

  if (isOutgoingMessage(msg)) {
    if (isHumanAgent(msg) && isPrivate(msg)) return 'nota_humana';
    if (isHumanAgent(msg)) return 'humano';
    if (isPrivate(msg)) return 'nota_interna';

    return 'bruna';
  }

  return 'sistema';
}

function roleLabel(role) {
  if (role === 'lead') return 'Lead';
  if (role === 'bruna') return nomeAgente || 'Bruna';
  if (role === 'humano') return 'Humano AuAu';
  if (role === 'nota_humana') return 'Nota Humana';
  if (role === 'nota_convertix') return 'Nota Convertix';
  return 'Sistema';
}

function contentForAttachmentOnly(msg, role) {
  const kind = getAttachmentKind(msg) || 'anexo';
  const id = toNumberOrNull(msg?.id);

  if (role === 'lead') {
    return `[ANEXO ${kind} recebido do lead | message_id: ${id || ''}]`;
  }

  if (role === 'humano' || role === 'bruna') {
    return `[ANEXO ${kind} enviado | message_id: ${id || ''}]`;
  }

  return `[ANEXO ${kind} | message_id: ${id || ''}]`;
}

function isAttachmentPlaceholderText(value) {
  /*
    Identifica texto técnico criado pelo fluxo para representar anexo.

    Esse texto NÃO é uma mensagem escrita pelo lead.
    Portanto, não pode fazer has_text virar true.
  */

  const t = norm(value);

  return (
    /^\[anexo\s+.+\|?\s*message_id:?\s*\d*\]$/.test(t) ||
    t.startsWith('[anexo ')
  );
}

function normalizeMessage(msg) {
  const isTranscript = isInternalAudioTranscription(msg);
  const referencedId = isTranscript ? extractAudioOriginalMessageId(msg) : null;
  const originalMsg = referencedId ? rawMessageMap.get(referencedId) : null;

  const id = isTranscript
    ? referencedId || toNumberOrNull(msg?.id)
    : toNumberOrNull(msg?.id);

  const role = roleFromMessage(msg, originalMsg);

  const originalContent = isTranscript
    ? extractAudioTranscriptionText(msg)
    : clean(msg?.content || '', true);

  const hasAttachment = getAttachments(msg).length > 0;
  const attachmentKind = getAttachmentKind(msg) || '';

  /*
    Regra importante:
    placeholder de anexo não conta como texto real.

    Se imagem/documento tem legenda real, has_text = true.
    Se só tem placeholder técnico, has_text = false.
  */

  let originalHasText =
    Boolean(clean(originalContent)) &&
    !isAttachmentPlaceholderText(originalContent);

  /*
    Se for mensagem sintética criada a partir do payload_base,
    respeita o has_text original que veio do fluxo principal.

    Isso evita transformar imagem_only em imagem_with_text só porque
    o content contém "[ANEXO image recebido...]".
  */

  if (msg.__synthetic_current_message === true && hasAttachment) {
    originalHasText =
      payloadMessage.has_text === true &&
      !isAttachmentPlaceholderText(originalContent);
  }

  let content = originalContent;

  if (!content || (hasAttachment && isAttachmentPlaceholderText(content) && !originalHasText)) {
    content = contentForAttachmentOnly(msg, role);
  }

  let messageModality = 'text_only';

  if (hasAttachment) {
    messageModality = originalHasText
      ? `${attachmentKind || 'attachment'}_with_text`
      : `${attachmentKind || 'attachment'}_only`;
  }

  return {
    id,
    content,
    role,
    role_label: roleLabel(role),
    content_attributes: msg?.content_attributes || {},
    created_at: msg?.created_at ?? null,
    private: msg?.private === true,
    has_text: originalHasText,
    has_attachment: hasAttachment,
    message_modality: messageModality,
    is_audio_transcription: isTranscript,
    is_synthetic_current_message: msg.__synthetic_current_message === true
  };
}

// ============================================================
// 7. REMOVE ÁUDIO ORIGINAL VAZIO QUANDO EXISTE TRANSCRIÇÃO
// ============================================================

const transcribedOriginalIds = new Set();

for (const msg of uniqueRawMessages) {
  if (isInternalAudioTranscription(msg)) {
    const originalId = extractAudioOriginalMessageId(msg);
    if (originalId) transcribedOriginalIds.add(originalId);
  }
}

// ============================================================
// 8. NORMALIZA, FILTRA E ORDENA MENSAGENS
// ============================================================

let chatwootMessages = uniqueRawMessages
  .filter(msg => !isDeletedMessage(msg))
  .filter(msg => !isTechnicalPrivateNote(msg))
  .filter(msg => {
    const id = toNumberOrNull(msg?.id);
    const hasEmptyContent = !clean(msg?.content || '', true);
    const hasAttachment = getAttachments(msg).length > 0;

    if (
      id &&
      transcribedOriginalIds.has(id) &&
      hasEmptyContent &&
      hasAttachment
    ) {
      return false;
    }

    return true;
  })
  .map(normalizeMessage)
  .filter(msg => msg.id !== null && msg.id !== undefined)
  .filter(msg => Number(msg.id) === currentMessageId || isRelevantText(msg.content, msg.role) || msg.has_attachment)
  .filter(msg => msg.role !== 'nota_interna')
  .sort((a, b) => Number(a.id) - Number(b.id));

// Dedup final por ID após normalização.
const normalizedById = new Map();

for (const msg of chatwootMessages) {
  normalizedById.set(Number(msg.id), msg);
}

chatwootMessages = Array.from(normalizedById.values())
  .sort((a, b) => Number(a.id) - Number(b.id));

// ============================================================
// 9. LIMITA JANELA ATÉ A MENSAGEM ATUAL
// ============================================================

let currentIndex = chatwootMessages.findIndex(msg => Number(msg.id) === currentMessageId);

if (currentIndex === -1) {
  currentIndex = chatwootMessages.length - 1;
}

let messagesUntilCurrent = currentIndex >= 0
  ? chatwootMessages.slice(0, currentIndex + 1)
  : chatwootMessages;

if (messagesUntilCurrent.length > qtdMessages) {
  messagesUntilCurrent = messagesUntilCurrent.slice(-qtdMessages);
}

const currentMessage = messagesUntilCurrent.find(msg => Number(msg.id) === currentMessageId)
  || messagesUntilCurrent[messagesUntilCurrent.length - 1]
  || null;

// ============================================================
// 10. MONTA BLOCO ATUAL CONTÍNUO DO LEAD
// ============================================================

let currentBlockMessages = [];

if (currentMessage) {
  const idx = messagesUntilCurrent.findIndex(msg => Number(msg.id) === Number(currentMessage.id));

  if (idx >= 0) {
    if (currentMessage.role === 'lead') {
      for (let i = idx; i >= 0; i--) {
        const msg = messagesUntilCurrent[i];

        if (msg.role === 'lead') {
          currentBlockMessages.unshift(msg);
          continue;
        }

        break;
      }
    } else {
      currentBlockMessages = [currentMessage];
    }
  }
}

const currentBlockStartId = currentBlockMessages.length
  ? currentBlockMessages[0].id
  : null;

const currentBlockEndId = currentBlockMessages.length
  ? currentBlockMessages[currentBlockMessages.length - 1].id
  : null;

const currentBlockStartIndex = currentBlockMessages.length
  ? messagesUntilCurrent.findIndex(msg => Number(msg.id) === Number(currentBlockStartId))
  : messagesUntilCurrent.length;

const beforeCurrentBlockMessages = currentBlockStartIndex > 0
  ? messagesUntilCurrent.slice(0, currentBlockStartIndex)
  : [];

const contextoAnteriorMessages = beforeCurrentBlockMessages
  .slice(-contextoAnteriorLimit);

const importantPrivateNotesBeforeBlock = beforeCurrentBlockMessages
  .filter(msg => msg.role === 'nota_convertix')
  .slice(-5);

function dedupeMessagesById(messages) {
  const map = new Map();

  for (const msg of messages) {
    if (!msg || msg.id === null || msg.id === undefined) continue;
    map.set(Number(msg.id), msg);
  }

  return Array.from(map.values())
    .sort((a, b) => Number(a.id) - Number(b.id));
}

const messagesForCrm = dedupeMessagesById([
  ...importantPrivateNotesBeforeBlock,
  ...contextoAnteriorMessages,
  ...currentBlockMessages
]);

// ============================================================
// 11. MONTA HISTÓRICO TEXTUAL PARA CRM
// ============================================================

function formatHistoryLine(msg) {
  const content = clean(msg.content, true);
  if (!content) return '';

  return `[${msg.id}] ${msg.role_label}: ${content}`;
}

function joinHistory(messages) {
  return messages
    .map(formatHistoryLine)
    .filter(Boolean)
    .join('\n');
}

const currentLeadBlockText = currentBlockMessages
  .map(msg => clean(msg.content, true))
  .filter(Boolean)
  .join('\n')
  .trim();

const historyForCrm = joinHistory(messagesForCrm);

// ============================================================
// 12. DESCOBRE ÚLTIMA MENSAGEM DA BRUNA ANTES DO BLOCO
// ============================================================

const beforeBlockMessages = currentBlockStartIndex > 0
  ? messagesUntilCurrent.slice(0, currentBlockStartIndex)
  : [];

function lastByRole(messages, role) {
  for (let i = messages.length - 1; i >= 0; i--) {
    if (messages[i].role === role) return messages[i];
  }

  return null;
}

const lastBrunaBeforeBlock = lastByRole(beforeBlockMessages, 'bruna');

// ============================================================
// 13. MONTA REPLY CONTEXT, SOMENTE QUANDO EXISTIR
// ============================================================

const normalizedMap = new Map();

for (const msg of messagesUntilCurrent) {
  normalizedMap.set(Number(msg.id), msg);
}

const replyContextForCurrentBlock = currentBlockMessages
  .map(msg => {
    const replyToId = toNumberOrNull(msg?.content_attributes?.in_reply_to);
    if (!replyToId) return null;

    const replied = normalizedMap.get(replyToId);

    if (!replied) {
      return {
        message_id: msg.id,
        message_text: clean(msg.content, true),
        in_reply_to: replyToId,
        replied_message_found: false
      };
    }

    return {
      message_id: msg.id,
      message_text: clean(msg.content, true),
      in_reply_to: replyToId,
      replied_message_found: true,
      replied_role: replied.role,
      replied_role_label: replied.role_label,
      replied_text: clean(replied.content, true)
    };
  })
  .filter(Boolean);

// ============================================================
// 14. MONTA SAÍDA ENXUTA PARA O ANALISTA CRM
// ============================================================

const finalContent = currentLeadBlockText || clean(
  payloadMessage.content || payloadMessage.content_raw || '',
  true
);

const lastBrunaBeforeBlockText = lastBrunaBeforeBlock
  ? clean(lastBrunaBeforeBlock.content, true)
  : clean(payloadInputs.mensagem_ultima_bruna || '', true);

const {
  qtd_messages: _dropQtdMessages,
  contexto_anterior_limit: _dropContextoAnteriorLimit,
  ...baseInputsWithoutTech
} = payloadBase.inputs || {};

const resumoLeadClean = cloneObj(baseInputsWithoutTech.resumo_lead);
resumoLeadClean.observacoes = dedupeObservationText(resumoLeadClean.observacoes);

const resumoInternoRepasseClean = cloneObj(baseInputsWithoutTech.resumo_interno_repasse);
resumoInternoRepasseClean.observacoes = dedupeObservationText(resumoInternoRepasseClean.observacoes);

const inputsClean = {
  ...baseInputsWithoutTech,

  resumo_lead: resumoLeadClean,
  resumo_interno_repasse: resumoInternoRepasseClean,

  mensagem_ultima_lead: finalContent,
  mensagem_ultima_bruna: lastBrunaBeforeBlockText,

  last_processed_message_id_candidate: currentMessageId,

  processar_IA: cfg.processar_IA === true
};

/*
  A modalidade da mensagem final precisa considerar o bloco inteiro,
  não só a última mensagem.

  Exemplo:
  Lead: imagem
  Lead: texto

  A última mensagem pode ser text_only, mas o bloco é image_with_text.
*/

const hasCurrentBlock = currentBlockMessages.length > 0;

const blockHasAttachment = hasCurrentBlock
  ? currentBlockMessages.some(msg => msg.has_attachment === true)
  : payloadMessage.has_attachment === true;

const blockHasRealText = hasCurrentBlock
  ? currentBlockMessages.some(msg => msg.has_text === true)
  : (
      payloadMessage.has_text === true ||
      (
        Boolean(clean(finalContent)) &&
        !isAttachmentPlaceholderText(finalContent)
      )
    );

const blockAttachmentKind =
  currentBlockMessages.find(msg => msg.has_attachment === true && msg.message_modality?.includes('image')) ? 'image' :
  currentBlockMessages.find(msg => msg.has_attachment === true && msg.message_modality?.includes('document')) ? 'document' :
  currentBlockMessages.find(msg => msg.has_attachment === true && msg.message_modality?.includes('audio')) ? 'audio' :
  currentBlockMessages.find(msg => msg.has_attachment === true && msg.message_modality?.includes('video')) ? 'video' :
  blockHasAttachment ? 'attachment' : '';

const blockMessageModality = !blockHasAttachment
  ? 'text_only'
  : blockHasRealText
    ? `${blockAttachmentKind}_with_text`
    : `${blockAttachmentKind}_only`;

const messageClean = {
  message_modality: blockMessageModality,
  has_text: blockHasRealText,
  has_attachment: blockHasAttachment,

  private: payloadBase.message?.private ?? false,
  type: payloadBase.message?.type || 'incoming',

  content: finalContent,
  content_raw: finalContent,

  created_at: payloadBase.message?.created_at || currentMessage?.created_at || '',
  historico: 'chatwoot',

  history_for_crm: historyForCrm,
  last_bruna_message_before_current_block: lastBrunaBeforeBlockText
};

if (replyContextForCurrentBlock.length > 0) {
  messageClean.reply_context_for_current_block = replyContextForCurrentBlock;
}

const chatwootClean = {
  chat_history_uuid: payloadBase.chatwoot?.chat_history_uuid || '',
  labels: Array.isArray(payloadBase.chatwoot?.labels) ? payloadBase.chatwoot.labels : [],

  system_event: payloadBase.chatwoot?.system_event || '',
  account_id: cfg.account_id || payloadBase.chatwoot?.account_id || null,
  contact_id: payloadBase.chatwoot?.contact_id || null,
  conversation_id: cfg.conversation_id || payloadBase.chatwoot?.conversation_id || null,
  message_id: currentMessageId || payloadBase.chatwoot?.message_id || null,

  event: payloadBase.chatwoot?.event || '',
  inbox_id: payloadBase.chatwoot?.inbox_id || null
};

const output = {
  inputs: inputsClean,
  message: messageClean,
  chatwoot: chatwootClean,
  memory: payloadBase.memory || {},
  lead: payloadBase.lead || {},
  agent_name: payloadBase.agent_name || nomeAgente,
  should_reply: payloadBase.should_reply !== false
};

// ============================================================
// 15. DEBUG OPCIONAL
// ============================================================

const includeDebug = cfg.debug === true || cfg.include_debug === true;

if (includeDebug) {
  output.prepara_contexto_crm_debug = {
    ok: true,
    node: 'PREPARA CONTEXTO CRM',

    raw_messages_received: rawMessages.length,
    raw_messages_unique: uniqueRawMessages.length,
    normalized_messages_total: chatwootMessages.length,
    messages_until_current: messagesUntilCurrent.length,

    qtd_messages_usado: qtdMessages,
    contexto_anterior_limit_usado: contextoAnteriorLimit,

    current_message_id: currentMessageId,
    current_message_found_in_chatwoot: rawHasCurrent,
    current_message_found_after_normalization: Boolean(currentMessage),

    current_block_start_id: currentBlockStartId,
    current_block_end_id: currentBlockEndId,
    current_block_messages_count: currentBlockMessages.length,

    contexto_anterior_messages_count: contextoAnteriorMessages.length,
    messages_for_crm_count: messagesForCrm.length,

    last_bruna_before_block_id: lastBrunaBeforeBlock?.id || null,

    reply_context_count: replyContextForCurrentBlock.length,

    roles_count: {
      lead: messagesUntilCurrent.filter(m => m.role === 'lead').length,
      bruna: messagesUntilCurrent.filter(m => m.role === 'bruna').length,
      humano: messagesUntilCurrent.filter(m => m.role === 'humano').length,
      nota_humana: messagesUntilCurrent.filter(m => m.role === 'nota_humana').length,
      nota_convertix: messagesUntilCurrent.filter(m => m.role === 'nota_convertix').length,
      sistema: messagesUntilCurrent.filter(m => m.role === 'sistema').length
    },

    important_private_notes_included: importantPrivateNotesBeforeBlock.length,

    audio_transcriptions_converted: messagesUntilCurrent.filter(m => m.is_audio_transcription).length,
    synthetic_current_message_used: messagesUntilCurrent.some(m => m.is_synthetic_current_message),

    current_lead_block_preview: finalContent.slice(0, 300),
    last_bruna_before_block_preview: lastBrunaBeforeBlockText.slice(0, 300)
  };
}

return [
  {
    json: output
  }
];

/*
  ============================================================
  NODE: VALIDA SAIDA CRM
  ============================================================

  Objetivo:
  Este node roda logo depois do Analista de CRM.

  Ele NÃO é um segundo analista.
  Ele NÃO deve tentar interpretar conversa, sexo, castração, raça,
  intenção, preço, múltiplos cães ou comportamento.

  Responsabilidades deste node:
  1. Garantir que a saída do Analista respeite o contrato esperado.
  2. Completar campos obrigatórios ausentes.
  3. Remover null de campos textuais.
  4. Normalizar booleanos.
  5. Validar enums oficiais de status, intenção e evento.
  6. Remover lixo técnico antigo de observações.
  7. Impedir incoerências operacionais óbvias, como agenda sem comprovante.
  8. Manter a decisão semântica principal com o Analista CRM.

  Regra de ouro:
  Código valida contrato.
  IA reconstrói estado.
*/

const item = $input.first().json || {};

const output = item.output && typeof item.output === 'object'
  ? { ...item.output }
  : {};

// ============================================================
// HELPERS GERAIS
// ============================================================

function cleanText(value) {
  return String(value ?? '')
    .replace(/\[object Object\]/gi, '')
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
    .replace(/\uFFFD/g, ' ')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .split('\n')
    .map(line => line.replace(/[ \t]+/g, ' ').trim())
    .filter(Boolean)
    .join('\n')
    .trim();
}

function cleanInline(value) {
  return cleanText(value)
    .replace(/\s+/g, ' ')
    .trim();
}

function norm(value) {
  return cleanInline(value)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase();
}

function toBool(value) {
  if (value === true) return true;
  if (value === false) return false;

  const v = norm(value);

  if (['true', '1', 'sim', 'yes', 's'].includes(v)) return true;
  if (['false', '0', 'nao', 'não', 'no', 'n', ''].includes(v)) return false;

  return Boolean(value);
}

function isKnown(value) {
  const v = cleanInline(value);
  const n = norm(v);

  return Boolean(v) &&
    ![
      'null',
      'undefined',
      'nao_informado',
      'nao_definido',
      'nao_definida',
      'não informado',
      'não definido',
      'não definida'
    ].includes(n);
}

function pickFirstKnown(...values) {
  for (const value of values) {
    if (isKnown(value)) return cleanInline(value);
  }

  return '';
}

function pickFirstKnownOrDefault(defaultValue, ...values) {
  for (const value of values) {
    if (isKnown(value)) return cleanInline(value);
  }

  return cleanInline(defaultValue);
}

function enumOrFallback(value, allowed, fallback) {
  const v = cleanInline(value);
  return allowed.includes(v) ? v : fallback;
}

function stripBadObservation(value) {
  const text = cleanInline(value);
  if (!text) return '';

  /*
    Remove frases técnicas antigas que não devem voltar para a memória.

    Importante:
    Não estamos tentando interpretar o lead aqui.
    Só estamos impedindo que lixo técnico de guard/debug contamine
    os próximos ciclos do CRM.
  */

  const bannedPatterns = [
    /bloqueado uso/i,
    /guard crm/i,
    /guard bloqueou/i,
    /corre[cç][aã]o aplicada/i,
    /baixa confian[cç]a inferida/i,
    /baixa confian[cç]a no sexo/i,
    /valida[cç][aã]o interna/i,
    /debug/i,
    /macho_nao_castrado por baixa confian/i,
    /hip[oó]tese de m[uú]ltiplos c[aã]es/i
  ];

  const sentences = text
    .split(/(?<=[.!?])\s+/)
    .map(s => s.trim())
    .filter(Boolean)
    .filter(sentence => !bannedPatterns.some(pattern => pattern.test(sentence)));

  return sentences.join(' ').trim();
}

function limitText(value, max = 500) {
  const text = cleanInline(value);
  if (text.length <= max) return text;
  return text.slice(0, max).trim();
}

