  cao_vacinas_ok: '',
  cao_antipulgas_ok: '',
  cao_sociavel: '',
  cao_reativo: '',
  unidade_preferida: '',
  servico_interesse: '',
  data_hora_avaliacao: '',
  comprovante_recebido: false,
  tipo_comprovante: '',
  observacoes: ''
};

const diagnosticoDefault = {
  ultima_mensagem_relevante_lead: '',
  ultima_mensagem_relevante_bruna: '',
  estado_reconstruido_com_base_em: '',
  alerta_conflito: false,
