};

// ============================================================
// NORMALIZA OBJETOS PRINCIPAIS
// ============================================================

output.resumo_lead = {
  ...resumoLeadDefault,
  ...(output.resumo_lead && typeof output.resumo_lead === 'object' ? output.resumo_lead : {})
};

output.resumo_interno_repasse = {
  ...repasseDefault,
  ...(output.resumo_interno_repasse && typeof output.resumo_interno_repasse === 'object' ? output.resumo_interno_repasse : {})
};

output.diagnostico_crm = {
  ...diagnosticoDefault,
  ...(output.diagnostico_crm && typeof output.diagnostico_crm === 'object' ? output.diagnostico_crm : {})
};

// ============================================================
// NORMALIZA CAMPOS DE TEXTO DO RESUMO
// ============================================================

for (const key of Object.keys(resumoLeadDefault)) {
  if (typeof resumoLeadDefault[key] === 'boolean') {
    output.resumo_lead[key] = toBool(output.resumo_lead[key]);
  } else {
    output.resumo_lead[key] = cleanInline(output.resumo_lead[key]);
  }
}

for (const key of Object.keys(repasseDefault)) {
  if (typeof repasseDefault[key] === 'boolean') {
    output.resumo_interno_repasse[key] = toBool(output.resumo_interno_repasse[key]);
  } else {
    output.resumo_interno_repasse[key] = cleanInline(output.resumo_interno_repasse[key]);
  }
}

for (const key of Object.keys(diagnosticoDefault)) {
  if (typeof diagnosticoDefault[key] === 'boolean') {
    output.diagnostico_crm[key] = toBool(output.diagnostico_crm[key]);
  } else {
    output.diagnostico_crm[key] = cleanInline(output.diagnostico_crm[key]);
  }
}

// ============================================================
// NORMALIZA CAMPOS DE TOPO
// ============================================================

output.status_lead = enumOrFallback(output.status_lead, STATUS_ALLOWED, 'QUALIFICANDO');
output.ultima_intencao = enumOrFallback(output.ultima_intencao, INTENCAO_ALLOWED, 'INFORMOU_DADOS_CAO');
output.evento_sistema = enumOrFallback(output.evento_sistema, EVENTO_ALLOWED, '');

output.apto_para_avaliacao = cleanInline(output.apto_para_avaliacao || 'pendente');
output.motivo_pre_reprovacao = cleanInline(output.motivo_pre_reprovacao);
output.status_pagamento = cleanInline(output.status_pagamento || 'nao_solicitado');
output.tipo_comprovante = cleanInline(output.tipo_comprovante || 'nao_informado');
output.arquivo_comprovante_referencia = cleanInline(output.arquivo_comprovante_referencia);
output.data_hora_avaliacao = cleanInline(output.data_hora_avaliacao);
output.data_hora_pre_reserva = cleanInline(output.data_hora_pre_reserva);
output.proxima_acao = cleanInline(output.proxima_acao);
output.motivo_repasse = cleanInline(output.motivo_repasse);

output.comprovante_recebido = toBool(output.comprovante_recebido);
output.pre_reserva_criada = toBool(output.pre_reserva_criada);
output.deve_repassar_humano = toBool(output.deve_repassar_humano);
output.deve_enviar_guia = toBool(output.deve_enviar_guia);
output.deve_solicitar_pagamento = toBool(output.deve_solicitar_pagamento);
output.deve_consultar_agenda = toBool(output.deve_consultar_agenda);
output.deve_criar_pre_reserva = toBool(output.deve_criar_pre_reserva);
output.deve_encerrar_conversa = toBool(output.deve_encerrar_conversa);

// ============================================================
// SINCRONIZA CAMPOS DUPLICADOS DE FORMA MECÂNICA
// ============================================================

/*
  Existem campos duplicados no topo e dentro de resumo_lead.
  Aqui não fazemos interpretação.
  Apenas garantimos que dados equivalentes não fiquem divergentes.
*/

output.resumo_lead.comprovante_recebido = toBool(
  output.resumo_lead.comprovante_recebido || output.comprovante_recebido
);

output.comprovante_recebido = toBool(
  output.comprovante_recebido || output.resumo_lead.comprovante_recebido
);

output.resumo_lead.tipo_comprovante = pickFirstKnownOrDefault(
  'nao_informado',
  output.resumo_lead.tipo_comprovante,
  output.tipo_comprovante
);

output.tipo_comprovante = pickFirstKnownOrDefault(
  'nao_informado',
  output.tipo_comprovante,
  output.resumo_lead.tipo_comprovante
);

output.resumo_interno_repasse.tipo_comprovante = pickFirstKnownOrDefault(
  'nao_informado',
  output.resumo_interno_repasse.tipo_comprovante,
  output.tipo_comprovante,
  output.resumo_lead.tipo_comprovante
);

output.resumo_lead.arquivo_comprovante_referencia = pickFirstKnown(
  output.resumo_lead.arquivo_comprovante_referencia,
  output.arquivo_comprovante_referencia
);

output.arquivo_comprovante_referencia = pickFirstKnown(
  output.arquivo_comprovante_referencia,
  output.resumo_lead.arquivo_comprovante_referencia
);

output.resumo_lead.data_hora_avaliacao = pickFirstKnown(
  output.resumo_lead.data_hora_avaliacao,
  output.data_hora_avaliacao
);

output.data_hora_avaliacao = pickFirstKnown(
  output.data_hora_avaliacao,
  output.resumo_lead.data_hora_avaliacao
);

output.resumo_lead.data_hora_pre_reserva = pickFirstKnown(
  output.resumo_lead.data_hora_pre_reserva,
  output.data_hora_pre_reserva
);

output.data_hora_pre_reserva = pickFirstKnown(
  output.data_hora_pre_reserva,
  output.resumo_lead.data_hora_pre_reserva
);

output.resumo_lead.pre_reserva_criada = toBool(
  output.resumo_lead.pre_reserva_criada || output.pre_reserva_criada
);

output.pre_reserva_criada = toBool(
  output.pre_reserva_criada || output.resumo_lead.pre_reserva_criada
);

// ============================================================
// OBSERVAÇÕES LIMPAS
// ============================================================

output.resumo_lead.observacoes = limitText(
  stripBadObservation(output.resumo_lead.observacoes),
  600
);

output.resumo_interno_repasse.observacoes = limitText(
  stripBadObservation(output.resumo_interno_repasse.observacoes),
  350
);

output.diagnostico_crm.descricao_conflito = limitText(
  stripBadObservation(output.diagnostico_crm.descricao_conflito),
  350
);

/*
  Fallback leve para observações.
  Não interpreta histórico.
  Só usa campos estruturados já definidos pelo Analista.
*/

if (!output.resumo_lead.observacoes) {
  const nome = output.resumo_lead.cao_nome;
  const dados = [];

  if (isKnown(output.resumo_lead.cao_raca)) dados.push(output.resumo_lead.cao_raca);
  if (isKnown(output.resumo_lead.cao_idade_anos)) dados.push(`${output.resumo_lead.cao_idade_anos} anos`);
  if (isKnown(output.resumo_lead.cao_porte)) dados.push(`porte ${output.resumo_lead.cao_porte}`);
  if (isKnown(output.resumo_lead.cao_sexo)) dados.push(output.resumo_lead.cao_sexo);
  if (isKnown(output.resumo_lead.cao_castrado)) dados.push(output.resumo_lead.cao_castrado);

  if (isKnown(nome) && dados.length) {
    output.resumo_lead.observacoes = `Lead informou ${nome}: ${dados.join(', ')}.`;
  } else if (dados.length) {
    output.resumo_lead.observacoes = `Lead informou dados do cão: ${dados.join(', ')}.`;
  }

  if (output.evento_sistema === 'ANEXO_RECEBIDO') {
    output.resumo_lead.observacoes = cleanInline(
      `${output.resumo_lead.observacoes} Anexo recebido; conteúdo do anexo não foi interpretado.`
    );
  }
}

if (!output.resumo_interno_repasse.observacoes) {
  const partes = [];

  if (isKnown(output.resumo_lead.cao_nome)) partes.push(output.resumo_lead.cao_nome);
  if (isKnown(output.resumo_lead.cao_raca)) partes.push(output.resumo_lead.cao_raca);
  if (isKnown(output.resumo_lead.cao_idade_anos)) partes.push(`${output.resumo_lead.cao_idade_anos} anos`);
  if (isKnown(output.resumo_lead.cao_porte)) partes.push(output.resumo_lead.cao_porte);
  if (isKnown(output.resumo_lead.cao_sexo)) partes.push(output.resumo_lead.cao_sexo);
  if (isKnown(output.resumo_lead.cao_castrado)) partes.push(output.resumo_lead.cao_castrado);

  let repasseObs = partes.length ? `${partes.join(', ')}.` : '';

  if (output.evento_sistema === 'ANEXO_RECEBIDO') {
    repasseObs = cleanInline(`${repasseObs} Anexo sem texto recebido.`);
  }

  output.resumo_interno_repasse.observacoes = repasseObs;
}

// ============================================================
// CONSISTÊNCIA OPERACIONAL MECÂNICA
// ============================================================

const comprovanteRecebido = toBool(output.comprovante_recebido);

const tentandoAgendaSemComprovante =
  !comprovanteRecebido &&
  (
    output.status_lead === 'AGUARDANDO_ESCOLHA_HORARIO' ||
    output.status_lead === 'PRE_RESERVA_CRIADA' ||
    output.evento_sistema === 'AGENDA_CONSULTADA' ||
    output.evento_sistema === 'HORARIOS_ENVIADOS' ||
    output.evento_sistema === 'PRE_RESERVA_CRIADA' ||
    output.deve_consultar_agenda === true ||
    output.deve_criar_pre_reserva === true ||
    output.pre_reserva_criada === true
  );

if (tentandoAgendaSemComprovante) {
  /*
    Aqui não inferimos intenção nem cobramos pagamento.
    Só removemos avanço de agenda impossível sem comprovante.
  */

  if (output.status_lead === 'AGUARDANDO_ESCOLHA_HORARIO' || output.status_lead === 'PRE_RESERVA_CRIADA') {
    output.status_lead = 'QUALIFICANDO';
  }

  if (['AGENDA_CONSULTADA', 'HORARIOS_ENVIADOS', 'PRE_RESERVA_CRIADA'].includes(output.evento_sistema)) {
    output.evento_sistema = '';
  }

  output.deve_consultar_agenda = false;
  output.deve_criar_pre_reserva = false;
  output.pre_reserva_criada = false;
  output.resumo_lead.pre_reserva_criada = false;
  output.data_hora_pre_reserva = '';
  output.resumo_lead.data_hora_pre_reserva = '';
}

/*
  Se encerrou por não perfil, não pode simultaneamente pedir pagamento,
  agenda ou pré-reserva.
*/

if (output.status_lead === 'ENCERRADO_NAO_PERFIL' || output.deve_encerrar_conversa === true) {
  output.deve_solicitar_pagamento = false;
  output.deve_consultar_agenda = false;
  output.deve_criar_pre_reserva = false;
  output.pre_reserva_criada = false;
  output.resumo_lead.pre_reserva_criada = false;
}

/*
  Se o evento atual é ANEXO_RECEBIDO sem comprovante confirmado,
  não pode avançar como comprovante identificado.
*/

if (output.evento_sistema === 'ANEXO_RECEBIDO' && !comprovanteRecebido) {
  output.comprovante_recebido = false;
  output.resumo_lead.comprovante_recebido = false;

  if (output.status_lead === 'COMPROVANTE_RECEBIDO') {
    output.status_lead = 'QUALIFICANDO';
  }
}

if (
  output.ultima_intencao === 'INTERESSE_CRECHE' &&
  (!output.resumo_lead.servico_interesse ||
    output.resumo_lead.servico_interesse === 'nao_definido')
) {
  output.resumo_lead.servico_interesse = 'creche';
}

if (
  output.ultima_intencao === 'INTERESSE_HOTEL' &&
  (!output.resumo_lead.servico_interesse ||
    output.resumo_lead.servico_interesse === 'nao_definido')
) {
  output.resumo_lead.servico_interesse = 'hotel';
}

// ============================================================
// DIAGNÓSTICO FINAL DO VALIDADOR
// ============================================================

/*
  ==================================================
  BLOCO FINAL DE CONSISTÊNCIA DO PAYLOAD DA BRUNA
  ==================================================

  Objetivo:
  Corrigir divergências internas do JSON gerado pela Bruna sem tentar adivinhar
  nada por texto livre.

  Este bloco NÃO lê:
  - message.content
  - history_for_crm
  - entry_channel
  - texto do lead
  - observações antigas

  Ele usa apenas dados estruturados já existentes:
  - output.resumo_lead
  - output.resumo_interno_repasse
  - item.inputs.resumo_lead, quando existir como estado anterior estruturado

  O que ele resolve:
  1. Preserva servico_interesse se já veio estruturado antes da Bruna.
  2. Sincroniza resumo_interno_repasse com resumo_lead.
  3. Padroniza campos vazios.
  4. Força agenda sempre vazia, porque a Bruna não agenda.
  5. Padroniza comprovante.
  6. Garante consistência básica de repasse humano.

  Onde colocar:
  No final do VALIDA SAIDA BRUNA, antes de:
  item.inputs = output;
  return [{ json: item }];
*/

output.resumo_lead = output.resumo_lead || {};
output.resumo_interno_repasse = output.resumo_interno_repasse || {};

const resumo = output.resumo_lead;
const repasse = output.resumo_interno_repasse;
const resumoEntrada = item.inputs?.resumo_lead || {};

/*
  Verifica se um campo tem valor realmente útil.

  Atenção:
  "nao_definido" e "nao_informado" são valores válidos em alguns campos,
  mas aqui usamos essa função apenas quando queremos saber se existe
  um valor informativo para preservar/copiar.
*/
function temValorUtil(valor) {
  const v = String(valor ?? '').trim();

  return (
    v !== '' &&
    v !== 'null' &&
    v !== 'undefined' &&
    v !== 'nao_definido' &&
    v !== 'nao_informado'
  );
}

/*
  1. Preserva servico_interesse sem inferência por texto.

  Ordem de prioridade:
  1. resumo_lead gerado pela Bruna
  2. resumo_interno_repasse gerado pela Bruna
  3. resumo_lead da entrada estruturada
  4. ultima_intencao quando for diretamente INTERESSE_CRECHE ou INTERESSE_HOTEL
  5. nao_definido

  Não tenta descobrir por conteúdo textual.
*/
if (!temValorUtil(resumo.servico_interesse)) {
  if (temValorUtil(repasse.servico_interesse)) {
    resumo.servico_interesse = repasse.servico_interesse;
  } else if (temValorUtil(resumoEntrada.servico_interesse)) {
    resumo.servico_interesse = resumoEntrada.servico_interesse;
  } else if (output.ultima_intencao === 'INTERESSE_CRECHE') {
    resumo.servico_interesse = 'creche';
  } else if (output.ultima_intencao === 'INTERESSE_HOTEL') {
    resumo.servico_interesse = 'hotel';
  } else {
    resumo.servico_interesse = 'nao_definido';
  }
}

/*
  Se a intenção atual é explicitamente interesse em creche ou hotel,
  ela pode preencher o serviço porque isso é dado estruturado, não inferência por texto.
*/
if (output.ultima_intencao === 'INTERESSE_CRECHE') {
  resumo.servico_interesse = 'creche';
}

if (output.ultima_intencao === 'INTERESSE_HOTEL') {
  resumo.servico_interesse = 'hotel';
}

/*
  2. Sincroniza resumo_interno_repasse com resumo_lead.

  O resumo interno não deve contradizer o resumo principal.
  Exemplo que isso corrige:
  resumo_lead.cao_porte = "mini"
  resumo_interno_repasse.cao_porte = "nao_definido"
*/
const camposParaEspelharNoRepasse = [
  'tutor_nome',
  'tutor_telefone',
  'cao_nome',
  'cao_idade_anos',
  'cao_raca',
  'cao_porte',
  'cao_sexo',
  'cao_castrado',
  'cao_vacinas_ok',
  'cao_antipulgas_ok',
  'cao_sociavel',
  'cao_reativo',
  'unidade_preferida',
  'servico_interesse',
  'comprovante_recebido',
  'tipo_comprovante'
];

for (const campo of camposParaEspelharNoRepasse) {
  const valorResumo = resumo[campo];

  if (typeof valorResumo === 'boolean' || temValorUtil(valorResumo)) {
    repasse[campo] = valorResumo;
  }

  if (repasse[campo] === null || repasse[campo] === undefined) {
    repasse[campo] = typeof valorResumo === 'boolean' ? false : '';
  }
}

/*
  3. Padroniza campos de enum.
*/

if (!temValorUtil(resumo.cao_porte)) resumo.cao_porte = 'nao_definido';
if (!temValorUtil(repasse.cao_porte)) repasse.cao_porte = resumo.cao_porte || 'nao_definido';

if (!temValorUtil(resumo.cao_sexo)) resumo.cao_sexo = 'nao_informado';
if (!temValorUtil(repasse.cao_sexo)) repasse.cao_sexo = resumo.cao_sexo || 'nao_informado';

if (!temValorUtil(resumo.cao_castrado)) resumo.cao_castrado = 'nao_informado';
if (!temValorUtil(repasse.cao_castrado)) repasse.cao_castrado = resumo.cao_castrado || 'nao_informado';

if (!temValorUtil(resumo.unidade_preferida)) resumo.unidade_preferida = 'nao_definida';
if (!temValorUtil(repasse.unidade_preferida)) repasse.unidade_preferida = resumo.unidade_preferida || 'nao_definida';

if (!temValorUtil(resumo.servico_interesse)) resumo.servico_interesse = 'nao_definido';
if (!temValorUtil(repasse.servico_interesse)) repasse.servico_interesse = resumo.servico_interesse || 'nao_definido';

/*
  4. Padroniza comprovante.

  Se comprovante_recebido = false, tipo_comprovante precisa ser nao_informado.
  Nada de string vazia.
*/
const comprovanteConfirmado = Boolean(resumo.comprovante_recebido || repasse.comprovante_recebido);

resumo.comprovante_recebido = comprovanteConfirmado;
repasse.comprovante_recebido = comprovanteConfirmado;

if (!comprovanteConfirmado) {
  resumo.tipo_comprovante = 'nao_informado';
  repasse.tipo_comprovante = 'nao_informado';
} else {
  if (!temValorUtil(resumo.tipo_comprovante)) resumo.tipo_comprovante = 'nao_informado';
  if (!temValorUtil(repasse.tipo_comprovante)) repasse.tipo_comprovante = resumo.tipo_comprovante || 'nao_informado';
}

/*
  5. Força agenda e pré-reserva vazias.

  A Bruna não agenda.
  A Bruna não consulta agenda.
  A Bruna não cria pré-reserva.
*/
output.deve_consultar_agenda = false;
output.deve_criar_pre_reserva = false;

resumo.data_hora_pre_reserva = '';
repasse.data_hora_avaliacao = '';

/*
  6. Consistência de repasse humano.
*/
if (output.deve_repassar_humano === true) {
  repasse.repassar_para = repasse.repassar_para || 'Flavia';

  if (!temValorUtil(output.motivo_repasse) && temValorUtil(repasse.motivo)) {
    output.motivo_repasse = repasse.motivo;
  }

  if (!temValorUtil(repasse.motivo) && temValorUtil(output.motivo_repasse)) {
    repasse.motivo = output.motivo_repasse;
  }

  if (!temValorUtil(output.motivo_repasse)) {
    output.motivo_repasse = 'Necessário repasse humano para continuidade do atendimento.';
  }

  if (!temValorUtil(repasse.motivo)) {
    repasse.motivo = output.motivo_repasse;
  }
} else {
  output.motivo_repasse = '';
  repasse.repassar_para = '';
  repasse.motivo = '';
}

/*
  7. Devolve os objetos corrigidos para o output.
*/
output.resumo_lead = resumo;
output.resumo_interno_repasse = repasse;

item.output = output;

item.valida_saida_crm_debug = {
  ok: true,
  node: 'VALIDA SAIDA CRM',
  status_lead: output.status_lead,
  ultima_intencao: output.ultima_intencao,
  evento_sistema: output.evento_sistema,
  comprovante_recebido: output.comprovante_recebido,
  pre_reserva_criada: output.pre_reserva_criada,
  observacoes_lead: output.resumo_lead.observacoes,
  observacoes_repasse: output.resumo_interno_repasse.observacoes
};

return [{ json: item }];

/*
  ============================================================
  NODE: APLICA CRM NO PAYLOAD
  ============================================================

  Objetivo:
  Este node roda depois do ANALISTA DE CRM e depois do VALIDA SAIDA CRM.

  O Analista/Validador devolve o estado reconstruído dentro de:
  - $json.output

  Mas a Bruna precisa receber novamente o contrato padrão do fluxo:
  - inputs
  - message
  - chatwoot
  - memory
  - lead
  - agent_name
  - should_reply

  Este node faz apenas a remontagem do payload.

  Ele NÃO interpreta conversa.
  Ele NÃO decide status.
  Ele NÃO mexe em sexo, castração, raça ou intenção.
  Ele NÃO carrega arrays gigantes de mensagens do Chatwoot para frente.

  Regra:
  - inputs recebe o output validado do CRM
  - message/chatwoot/memory/lead vêm do PREPARA CONTEXTO CRM
  - histórico textual útil é preservado
  - arrays pesados e debug interno são removidos
*/

const current = $input.first().json || {};

/*
  Saída validada do CRM.

  Esperado:
  {
    output: { ...estado reconstruído... }
  }
*/

const crmOutput = current.output && typeof current.output === 'object'
  ? current.output
  : null;

if (!crmOutput) {
  throw new Error('APLICA CRM NO PAYLOAD: $json.output não encontrado ou inválido.');
}

/*
  Base limpa criada no PREPARA CONTEXTO CRM.

  Ela contém o payload padrão:
  - inputs
  - message
  - chatwoot
  - memory
  - lead
  - agent_name
  - should_reply

  Se em alguma versão o PREPARA CONTEXTO CRM ainda devolver payload_base,
  usamos payload_base como fallback.
*/

const preparaContexto = $('PREPARA CONTEXTO CRM').first().json || {};

const base =
  preparaContexto.payload_base && typeof preparaContexto.payload_base === 'object'
    ? preparaContexto.payload_base
    : preparaContexto;

// ============================================================
// HELPERS
// ============================================================

function cloneObject(value) {
  if (!value || typeof value !== 'object') return {};
  return JSON.parse(JSON.stringify(value));
}

function cleanText(value) {
  return String(value ?? '')
    .replace(/\[object Object\]/gi, '')
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
    .replace(/\uFFFD/g, ' ')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .trim();
}

function cleanInline(value) {
  return cleanText(value)
    .replace(/\s+/g, ' ')
    .trim();
}

function numberOrNull(value) {
  const n = Number(value);
  return Number.isFinite(n) && n > 0 ? n : null;
}

function extractFirstMessageIdFromHistory(history) {
  const text = String(history ?? '');
  const match = text.match(/^\[(\d+)\]/m);
  return match ? Number(match[1]) : null;
}

function extractLastRoleMessageFromHistory(history, roleLabel) {
  const text = String(history ?? '');
  const lines = text.split('\n').map(x => x.trim()).filter(Boolean);

  for (let i = lines.length - 1; i >= 0; i--) {
    const line = lines[i];
    const pattern = new RegExp(`^\\[\\d+\\]\\s*${roleLabel}:\\s*(.+)$`, 'i');
    const match = line.match(pattern);

    if (match?.[1]) {
      return match[1].trim();
    }
  }

  return '';
}

// ============================================================
// RECONSTRÓI SEÇÕES BASE
// ============================================================

const message = cloneObject(base.message);
const chatwoot = cloneObject(base.chatwoot);
const memory = cloneObject(base.memory);
const lead = cloneObject(base.lead);

/*
  Remove campos pesados do Chatwoot.

  A Bruna e o próximo fluxo não precisam receber lista bruta de mensagens,
  attachments ou arrays usados apenas para análise do CRM.
*/

delete chatwoot.chatwoot_messages;
delete chatwoot.chatwoot_messages_all;
delete chatwoot.messages_for_crm;
delete chatwoot.current_lead_block_messages;
delete chatwoot.contexto_anterior_messages;

/*
  Também evita carregar possíveis arrays pesados se alguma versão antiga
  colocou esses campos diretamente na raiz.
*/

delete message.chatwoot_messages;
delete message.chatwoot_messages_all;
delete message.messages_for_crm;
delete message.current_lead_block_messages;
delete message.contexto_anterior_messages;
delete message.attachments;

// ============================================================
// PRESERVA CONTEXTO TEXTUAL ÚTIL PARA AUDITORIA/BRUNA
// ============================================================

message.historico = 'historico';

message.content = cleanText(
  message.content ||
  preparaContexto.current_lead_block_text ||
  preparaContexto.message?.content ||
  ''
);

message.content_raw = cleanText(
  message.content_raw ||
  message.content ||
  ''
);

message.history_for_crm = cleanText(
  message.history_for_crm ||
  preparaContexto.history_for_crm ||
  preparaContexto.message?.history_for_crm ||
  ''
);

message.current_lead_block_text = cleanText(
  message.current_lead_block_text ||
  preparaContexto.current_lead_block_text ||
  message.content ||
  ''
);

message.last_bruna_message_before_current_block = cleanText(
  message.last_bruna_message_before_current_block ||
  preparaContexto.last_bruna_message_before_current_block ||
  preparaContexto.message?.last_bruna_message_before_current_block ||
  ''
);

message.last_human_message_before_current_block = cleanText(
  message.last_human_message_before_current_block ||
  preparaContexto.last_human_message_before_current_block ||
  preparaContexto.message?.last_human_message_before_current_block ||
  extractLastRoleMessageFromHistory(message.history_for_crm, 'Humano AuAu') ||
  ''
);

message.last_human_note_before_current_block = cleanText(
  message.last_human_note_before_current_block ||
  preparaContexto.last_human_note_before_current_block ||
  preparaContexto.message?.last_human_note_before_current_block ||
  extractLastRoleMessageFromHistory(message.history_for_crm, 'Nota Humana') ||
  ''
);

/*
  IDs úteis para auditoria.
*/

message.current_message_id = numberOrNull(
  message.current_message_id ||
  preparaContexto.current_message_id ||
  chatwoot.message_id
);

message.first_message_id = numberOrNull(
  message.first_message_id ||
  preparaContexto.first_message_id ||
  preparaContexto.message?.first_message_id ||
  extractFirstMessageIdFromHistory(message.history_for_crm)
);

message.last_message_id = numberOrNull(
  message.last_message_id ||
  preparaContexto.last_message_id ||
  preparaContexto.message?.last_message_id ||
  chatwoot.message_id
);

/*
  Garante modalidade mínima.
*/

message.message_modality = cleanInline(
  message.message_modality ||
  preparaContexto.message?.message_modality ||
  ''
);

message.has_text = Boolean(
  message.has_text ??
  preparaContexto.message?.has_text ??
  cleanText(message.content)
);

message.has_attachment = Boolean(
  message.has_attachment ??
  preparaContexto.message?.has_attachment ??
  false
);

// ============================================================
// MONTA PAYLOAD FINAL
// ============================================================

const finalPayload = {
  inputs: crmOutput,
  message,
  chatwoot,
  memory,
  lead,
  agent_name: base.agent_name || preparaContexto.agent_name || 'Bruna',
  should_reply: base.should_reply !== false
};

/*
  Debug leve.
  Não carrega histórico gigante nem mensagem bruta.
*/

finalPayload.aplica_crm_payload_debug = {
  ok: true,
  node: 'APLICA CRM NO PAYLOAD',
  status_lead: crmOutput.status_lead || '',
  ultima_intencao: crmOutput.ultima_intencao || '',
  evento_sistema: crmOutput.evento_sistema || '',
  current_message_id: message.current_message_id,
  first_message_id: message.first_message_id,
  last_message_id: message.last_message_id,
  has_history_for_crm: Boolean(message.history_for_crm),
};

/*
  Se quiser passar o debug do validador para inspeção temporária,
  mantém aqui. Depois que estabilizar, pode apagar esse bloco.
*/

if (current.valida_saida_crm_debug) {
  finalPayload.valida_saida_crm_debug = current.valida_saida_crm_debug;
}

return [
  {
    json: finalPayload
  }
];
